    }
}

/// Handle a single parsed input event.
pub fn handleEvent(scr: *Screen, event: InputEvent) void {
    switch (event) {
        .print => |cp| {
            var w = Writer.init(scr);
            w.putChar(cp);
        },
        .c0 => |c| handleC0(scr, c),
        .csi => |csi| handleCSI(scr, csi),
        .esc => |esc| handleESC(scr, esc),
        .osc => |osc| handleOSC(scr, osc),
        .dcs => |dcs| handleDCS(scr, dcs),
    }
}

fn handleC0(scr: *Screen, c: u8) void {
    var w = Writer.init(scr);
    switch (c) {
        0x07 => {}, // BEL - bell
        0x08 => w.backspace(), // BS
        0x09 => w.tab(), // HT
        0x0A, 0x0B, 0x0C => w.linefeed(), // LF, VT, FF
        0x0D => w.carriageReturn(), // CR
        0x0E => {}, // SO - shift out (ACS)
        0x0F => {}, // SI - shift in
        else => {},
    }
}

fn handleCSI(scr: *Screen, csi: CSI) void {
    // Check for private mode marker
    if (csi.intermediate_count > 0 and csi.intermediates[0] == '?') {
        handleCSIPrivate(scr, csi);
        return;
    }

    // DECSCUSR: CSI Ps SP q — set cursor style
    if (csi.intermediate_count > 0 and csi.intermediates[0] == ' ' and csi.final == 'q') {
        const style = csi.getParam(0, 0);
        if (style <= 6) {
            scr.cstyle = @enumFromInt(@as(u3, @intCast(style)));
        }
        return;
    }

    var w = Writer.init(scr);
    switch (csi.final) {
        'A' => { // CUU - cursor up
            scr.cursorUp(csi.getParam(0, 1));
        },
        'B' => { // CUD - cursor down
            scr.cursorDown(csi.getParam(0, 1));
        },
        'C' => { // CUF - cursor forward
            const n = csi.getParam(0, 1);
            scr.cx = @min(scr.cx + n, scr.grid.cols -| 1);
        },
        'D' => { // CUB - cursor back
            const n = csi.getParam(0, 1);
            scr.cx = if (scr.cx >= n) scr.cx - n else 0;
        },
        'E' => { // CNL - cursor next line
            scr.cursorDown(csi.getParam(0, 1));
            scr.cx = 0;
        },
        'F' => { // CPL - cursor previous line
            scr.cursorUp(csi.getParam(0, 1));
            scr.cx = 0;
        },
        'G' => { // CHA - cursor character absolute
            const col = csi.getParam(0, 1);
            scr.cx = @min(if (col > 0) col - 1 else 0, scr.grid.cols -| 1);
        },
        'H', 'f' => { // CUP/HVP - cursor position
            const row = csi.getParam(0, 1);
            const col = csi.getParam(1, 1);
            scr.cursorTo(if (col > 0) col - 1 else 0, if (row > 0) row - 1 else 0);
        },
        'J' => { // ED - erase display
            const mode_param = csi.getParam(0, 0);
            switch (mode_param) {
                0 => w.eraseToEnd(),
                1 => w.eraseToStart(),
                2 => w.eraseScreen(),
                else => {},
            }
        },
        'K' => { // EL - erase line
            const mode_param = csi.getParam(0, 0);
            switch (mode_param) {
                0 => w.eraseToEol(),
                1 => w.eraseToBol(),
                2 => w.eraseLine(),
                else => {},
            }
        },
        'L' => { // IL - insert lines
            w.insertLines(csi.getParam(0, 1));
        },
        'M' => { // DL - delete lines
            w.deleteLines(csi.getParam(0, 1));
        },
        'P' => { // DCH - delete characters
            w.deleteChars(csi.getParam(0, 1));
        },
        'S' => { // SU - scroll up
            scr.scrollUp(csi.getParam(0, 1));
        },
        'T' => { // SD - scroll down
            scr.scrollDown(csi.getParam(0, 1));"}

{"content":"const std = @import("std");
const grid_mod = @import("grid.zig");
const screen_mod = @import("screen.zig");
const output_mod = @import("../terminal/output.zig");
const colour = @import("../core/colour.zig");

const Cell = grid_mod.Cell;
const Screen = screen_mod.Screen;
const Output = output_mod.Output;

/// Tracks which lines need redrawing.
pub const DirtyTracker = struct {
    dirty: []bool,
    force_full: bool,
    allocator: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator, rows: u32) !DirtyTracker {
        const dirty = try alloc.alloc(bool, rows);
        @memset(dirty, true); // initially everything is dirty
        return .{
            .dirty = dirty,
            .force_full = true,
            .allocator = alloc,
        };
    }

    pub fn deinit(self: *DirtyTracker) void {
        self.allocator.free(self.dirty);
    }

    pub fn markDirty(self: *DirtyTracker, y: u32) void {
        if (y < self.dirty.len) self.dirty[y] = true;
    }

    pub fn markAllDirty(self: *DirtyTracker) void {
        @memset(self.dirty, true);
        self.force_full = true;
    }

    pub fn isDirty(self: *const DirtyTracker, y: u32) bool {
        if (self.force_full) return true;
        if (y >= self.dirty.len) return false;
        return self.dirty[y];
    }

    pub fn clearDirty(self: *DirtyTracker) void {
        @memset(self.dirty, false);
        self.force_full = false;
    }

    pub fn resize(self: *DirtyTracker, new_rows: u32) !void {
        const new_dirty = try self.allocator.alloc(bool, new_rows);
        @memset(new_dirty, true);
        self.allocator.free(self.dirty);
        self.dirty = new_dirty;
        self.force_full = true;
    }
};

/// Redraw dirty lines from screen to output.
pub fn redraw(tracker: *DirtyTracker, scr: *Screen, out: *Output) void {
    var cur_fg: colour.Colour = .default;
    var cur_bg: colour.Colour = .default;
    var cur_attrs: colour.Attributes = .{};

    // Reset attributes at start
    out.attrReset();

    var y: u32 = 0;
    while (y < scr.grid.rows) : (y += 1) {
        if (!tracker.isDirty(y)) continue;

        out.cursorTo(0, y);
        const line = scr.grid.getLine(y);

        var x: u32 = 0;
        while (x < scr.grid.cols) : (x += 1) {
            const cell = &line.cells[x];

            // Skip empty cells (width 0, used for wide char continuation)
            if (cell.width == 0 and cell.codepoint == 0) {
                continue;
            }

            // Update attributes if changed
            if (@as(u16, @bitCast(cell.attrs)) != @as(u16, @bitCast(cur_attrs))) {
                out.attrReset();
                out.setAttrs(cell.attrs);
                cur_fg = .default;
                cur_bg = .default;
                cur_attrs = cell.attrs;
            }

            // Update colors if changed
            if (!colourEql(cell.fg, cur_fg)) {
                out.setFg(cell.fg);
                cur_fg = cell.fg;
            }
            if (!colourEql(cell.bg, cur_bg)) {
                out.setBg(cell.bg);
                cur_bg = cell.bg;
            }

            // Write character
            if (cell.codepoint >= 0x20) {
                var utf8_buf: [4]u8 = undefined;
                const len = std.unicode.utf8Encode(cell.codepoint, &utf8_buf) catch 1;
                out.writeBytes(utf8_buf[0..len]);
            } else {
                out.writeBytes(" ");
            }
        }

        // Clear to end of line
        out.clearToEol();
    }

    // Position cursor
    out.cursorTo(scr.cx, scr.cy);

    // Show/hide cursor and set cursor style
    if (scr.mode.cursor_visible) {
        out.showCursor();
        out.setCursorStyle(@intFromEnum(scr.cstyle));
    } else {
        out.hideCursor();
    }

    out.flush();
    tracker.clearDirty();
}

fn colourEql(a: colour.Colour, b: colour.Colour) bool {
    return switch (a) {
        .default => switch (b) {
            .default => true,
            else => false,
        },
        .palette => |pa| switch (b) {
            .palette => |pb| pa == pb,
            else => false,
        },
        .rgb => |ra| switch (b) {
            .rgb => |rb| ra.r == rb.r and ra.g == rb.g and ra.b == rb.b,
            else => false,
        },
    };
}

/// Redraw dirty lines from screen to output at a given offset within a larger composed view.
pub fn redrawAt(tracker: *DirtyTracker, scr: *Screen, out: *Output, xoff: u32, yoff: u32) void {
    var cur_fg: colour.Colour = .default;
    var cur_bg: colour.Colour = .default;
    var cur_attrs: colour.Attributes = .{};

    var y: u32 = 0;
    while (y < scr.grid.rows) : (y += 1) {
        if (!tracker.isDirty(y)) continue;

        out.cursorTo(xoff, yoff + y);
        const line = scr.grid.getLine(y);

        var x: u32 = 0;
        while (x < scr.grid.cols) : (x += 1) {
            const cell = &line.cells[x];

            if (cell.width == 0 and cell.codepoint == 0) continue;

            if (@as(u16, @bitCast(cell.attrs)) != @as(u16, @bitCast(cur_attrs))) {
                out.attrReset();"}

{"content":"const std = @import("std");
const grid_mod = @import("grid.zig");
const colour = @import("../core/colour.zig");

pub const Grid = grid_mod.Grid;
pub const Cell = grid_mod.Cell;
pub const Line = grid_mod.Line;

/// Cursor style.
pub const CursorStyle = enum(u3) {
    default = 0,
    blinking_block = 1,
    steady_block = 2,
    blinking_underline = 3,
    steady_underline = 4,
    blinking_bar = 5,
    steady_bar = 6,
};

/// Screen mode flags (DEC private modes, etc.).
pub const Mode = packed struct(u32) {
    cursor_visible: bool = true,
    insert: bool = false,
    origin: bool = false,
    wrap: bool = true,
    mouse_standard: bool = false,
    mouse_button: bool = false,
    mouse_any: bool = false,
    mouse_sgr: bool = false,
    app_cursor: bool = false,
    app_keypad: bool = false,
    bracketed_paste: bool = false,
    focus_events: bool = false,
    alt_screen: bool = false,
    _padding: u19 = 0,

    pub const default: Mode = .{};
};

/// Saved cursor state for DECSC/DECRC.
const SavedState = struct {
    cx: u32 = 0,
    cy: u32 = 0,
    cell: Cell = Cell.blank,
    origin_mode: bool = false,
};

/// Screen represents the visible terminal state.
/// Each pane has its own Screen instance.
pub const Screen = struct {
    grid: Grid,

    /// Cursor position.
    cx: u32,
    cy: u32,

    /// Cursor style and color.
    cstyle: CursorStyle,
    default_cstyle: CursorStyle,

    /// Scroll region (top and bottom, inclusive).
    rupper: u32,
    rlower: u32,

    /// Current cell attributes for new characters.
    cell: Cell,

    /// Screen modes.
    mode: Mode,
    default_mode: Mode,

    /// Saved state for DECSC/DECRC.
    saved: SavedState,

    /// Alt-screen backing grid (created on first use).
    alt_grid: ?Grid,
    alt_saved: SavedState,

    /// Title.
    title: ?[]const u8,

    allocator: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator, init_cols: u32, init_rows: u32, hlimit: u32) Screen {
        return .{
            .grid = Grid.init(alloc, init_cols, init_rows, hlimit),
            .cx = 0,
            .cy = 0,
            .cstyle = .steady_bar,
            .default_cstyle = .steady_bar,
            .rupper = 0,
            .rlower = init_rows -| 1,
            .cell = Cell.blank,
            .mode = Mode.default,
            .default_mode = Mode.default,
            .saved = .{},
            .alt_grid = null,
            .alt_saved = .{},
            .title = null,
            .allocator = alloc,
        };
    }

    pub fn deinit(self: *Screen) void {
        self.grid.deinit();
        if (self.alt_grid) |*ag| {
            ag.deinit();
        }
        if (self.title) |t| {
            self.allocator.free(t);
        }
    }

    /// Get grid dimensions.
    pub fn cols(self: *const Screen) u32 {
        return self.grid.cols;
    }

    pub fn rows(self: *const Screen) u32 {
        return self.grid.rows;"}

{"content":"const std = @import("std");
const colour = @import("../core/colour.zig");

/// Terminal output writer.
/// Buffers escape sequences and text to be written to a file descriptor.
pub const Output = struct {
    buf: [8192]u8 = undefined,
    len: usize = 0,
    fd: std.c.fd_t,

    pub fn init(fd: std.c.fd_t) Output {
        return .{ .fd = fd };
    }

    /// Flush buffered output to the fd.
    pub fn flush(self: *Output) void {
        if (self.len == 0) return;
        _ = std.c.write(self.fd, &self.buf, self.len);
        self.len = 0;
    }

    /// Write raw bytes, flushing if buffer is full.
    pub fn writeBytes(self: *Output, data: []const u8) void {
        var remaining = data;
        while (remaining.len > 0) {
            const space = self.buf.len - self.len;
            if (space == 0) {
                self.flush();
                continue;
            }
            const n = @min(remaining.len, space);
            @memcpy(self.buf[self.len..][0..n], remaining[0..n]);
            self.len += n;
            remaining = remaining[n..];
        }
    }

    /// Write a formatted string.
    pub fn print(self: *Output, comptime fmt: []const u8, args: anytype) void {
        var tmp: [1024]u8 = undefined;
        const s = std.fmt.bufPrint(&tmp, fmt, args) catch return;
        self.writeBytes(s);
    }

    // -- Cursor movement --

    /// Move cursor to (col, row), 0-based.
    pub fn cursorTo(self: *Output, col: u32, row: u32) void {
        self.print("\x1b[{d};{d}H", .{ row + 1, col + 1 });
    }

    /// Move cursor up by n.
    pub fn cursorUp(self: *Output, n: u32) void {
        if (n > 0) self.print("\x1b[{d}A", .{n});
    }

    /// Move cursor down by n.
    pub fn cursorDown(self: *Output, n: u32) void {
        if (n > 0) self.print("\x1b[{d}B", .{n});
    }

    /// Move cursor forward by n.
    pub fn cursorForward(self: *Output, n: u32) void {
        if (n > 0) self.print("\x1b[{d}C", .{n});
    }

    /// Move cursor back by n.
    pub fn cursorBack(self: *Output, n: u32) void {
        if (n > 0) self.print("\x1b[{d}D", .{n});
    }

    // -- Attributes --

    /// Reset all attributes.
    pub fn attrReset(self: *Output) void {
        self.writeBytes("\x1b[0m");
    }

    /// Set foreground color.
    pub fn setFg(self: *Output, c: colour.Colour) void {
        self.writeSgrColour(c, true);
    }

    /// Set background color.
    pub fn setBg(self: *Output, c: colour.Colour) void {
        self.writeSgrColour(c, false);
    }

    fn writeSgrColour(self: *Output, c: colour.Colour, is_fg: bool) void {
        var tmp: [32]u8 = undefined;
        const s = switch (c) {
            .default => std.fmt.bufPrint(&tmp, "\x1b[{d}m", .{if (is_fg) @as(u8, 39) else @as(u8, 49)}) catch return,
            .palette => |idx| blk: {
                if (idx < 8) {
                    break :blk std.fmt.bufPrint(&tmp, "\x1b[{d}m", .{(if (is_fg) @as(u8, 30) else @as(u8, 40)) + idx}) catch return;
                } else if (idx < 16) {
                    break :blk std.fmt.bufPrint(&tmp, "\x1b[{d}m", .{(if (is_fg) @as(u8, 90) else @as(u8, 100)) + idx - 8}) catch return;
                } else {
                    const base: u8 = if (is_fg) 38 else 48;
                    break :blk std.fmt.bufPrint(&tmp, "\x1b[{d};5;{d}m", .{ base, idx }) catch return;
                }
            },
            .rgb => |rgb| blk: {
                const base: u8 = if (is_fg) 38 else 48;
                break :blk std.fmt.bufPrint(&tmp, "\x1b[{d};2;{d};{d};{d}m", .{ base, rgb.r, rgb.g, rgb.b }) catch return;
            },
        };
        self.writeBytes(s);
    }

    /// Set attributes (bold, italic, etc.).
    pub fn setAttrs(self: *Output, attrs: colour.Attributes) void {
        if (attrs.bold) self.writeBytes("\x1b[1m");
        if (attrs.dim) self.writeBytes("\x1b[2m");
        if (attrs.italic) self.writeBytes("\x1b[3m");
        if (attrs.underline) self.writeBytes("\x1b[4m");
        if (attrs.blink) self.writeBytes("\x1b[5m");
        if (attrs.reverse) self.writeBytes("\x1b[7m");
        if (attrs.hidden) self.writeBytes("\x1b[8m");
        if (attrs.strikethrough) self.writeBytes("\x1b[9m");
    }

    // -- Screen operations --

    /// Clear entire screen.
    pub fn clearScreen(self: *Output) void {
        self.writeBytes("\x1b[2J");
    }

    /// Clear from cursor to end of screen.
    pub fn clearToEnd(self: *Output) void {
        self.writeBytes("\x1b[J");
    }

    /// Clear from cursor to end of line.
    pub fn clearToEol(self: *Output) void {
        self.writeBytes("\x1b[K");
    }

    /// Clear entire line.
    pub fn clearLine(self: *Output) void {
        self.writeBytes("\x1b[2K");
    }

    /// Set scroll region.
    pub fn setScrollRegion(self: *Output, top: u32, bottom: u32) void {
        self.print("\x1b[{d};{d}r", .{ top + 1, bottom + 1 });
    }

    /// Scroll up by n lines.
    pub fn scrollUp(self: *Output, n: u32) void {
        if (n > 0) self.print("\x1b[{d}S", .{n});
    }

    /// Scroll down by n lines.
    pub fn scrollDown(self: *Output, n: u32) void {
        if (n > 0) self.print("\x1b[{d}T", .{n});
    }

    // -- Cursor visibility --

    pub fn hideCursor(self: *Output) void {
        self.writeBytes("\x1b[?25l");
    }

    pub fn showCursor(self: *Output) void {
        self.writeBytes("\x1b[?25h");
    }

    /// Set cursor style via DECSCUSR (ESC [ Ps SP q).
    pub fn setCursorStyle(self: *Output, style: u3) void {
        self.print("\x1b[{d} q", .{@as(u32, style)});
    }

    // -- Alternate screen buffer --

    pub fn enterAltScreen(self: *Output) void {
        self.writeBytes("\x1b[?1049h");
    }

    pub fn leaveAltScreen(self: *Output) void {
        self.writeBytes("\x1b[?1049l");
    }

    // -- Mouse --

    pub fn enableMouseSGR(self: *Output) void {
        self.writeBytes("\x1b[?1006h");
    }

    pub fn disableMouseSGR(self: *Output) void {
        self.writeBytes("\x1b[?1006l");
    }

    pub fn enableMouseAll(self: *Output) void {
        self.writeBytes("\x1b[?1003h");
    }

    pub fn disableMouseAll(self: *Output) void {
        self.writeBytes("\x1b[?1003l");
    }

    // -- Bracketed paste --

    pub fn enableBracketedPaste(self: *Output) void {
        self.writeBytes("\x1b[?2004h");
    }

    pub fn disableBracketedPaste(self: *Output) void {
        self.writeBytes("\x1b[?2004l");"}

